const { test } = require('node:test');
const assert = require('node:assert');
const crypto = require('node:crypto');
const fs = require('node:fs');
const http = require('node:http');
const path = require('node:path');
const { app } = require('../server');

const webhookSecret = fs.readFileSync(path.join(__dirname, '../data/webhook-secret.txt'), 'utf8').trim();

function startServer() {
  return new Promise((resolve) => {
    const server = http.createServer(app);
    server.listen(0, () => resolve(server));
  });
}

function get(server, path) {
  return new Promise((resolve, reject) => {
    const { port } = server.address();
    http
      .get(`http://127.0.0.1:${port}${path}`, (res) => {
        let body = '';
        res.on('data', (chunk) => (body += chunk));
        res.on('end', () => resolve({ status: res.statusCode, body: JSON.parse(body) }));
      })
      .on('error', reject);
  });
}

function post(server, path, rawBody, headers) {
  return new Promise((resolve, reject) => {
    const { port } = server.address();
    const request = http.request(
      `http://127.0.0.1:${port}${path}`,
      { method: 'POST', headers },
      (res) => {
        let body = '';
        res.on('data', (chunk) => (body += chunk));
        res.on('end', () => resolve({ status: res.statusCode, body: JSON.parse(body) }));
      },
    );
    request.on('error', reject);
    request.end(rawBody);
  });
}

function webhookHeaders(rawBody) {
  return {
    'Content-Type': 'application/json',
    'X-Signature': crypto.createHmac('sha256', webhookSecret).update(rawBody).digest('hex'),
  };
}

test('GET /health returns ok', async () => {
  const server = await startServer();
  try {
    const { status, body } = await get(server, '/health');
    assert.strictEqual(status, 200);
    assert.deepStrictEqual(body, { status: 'ok' });
  } finally {
    server.close();
  }
});

test('GET /items returns list', async () => {
  const server = await startServer();
  try {
    const { status, body } = await get(server, '/items');
    assert.strictEqual(status, 200);
    assert.ok(Array.isArray(body.items));
    assert.ok(body.items.length >= 2);
  } finally {
    server.close();
  }
});

test('GET /items/:id returns 404 for missing', async () => {
  const server = await startServer();
  try {
    const { status, body } = await get(server, '/items/99999');
    assert.strictEqual(status, 404);
    assert.strictEqual(body.error, 'not_found');
  } finally {
    server.close();
  }
});

test('POST /webhook accepts a valid signed event', async () => {
  const server = await startServer();
  const rawBody = '{ "type": "item.updated", "data": {"itemId": 1}, "timestamp": 1720000000, "id": "webhook-happy-path" }';
  try {
    const { status, body } = await post(server, '/webhook', rawBody, webhookHeaders(rawBody));
    assert.strictEqual(status, 200);
    assert.deepStrictEqual(body, { accepted: true, id: 'webhook-happy-path' });
  } finally {
    server.close();
  }
});

test('POST /webhook rejects a replayed event', async () => {
  const server = await startServer();
  const rawBody = JSON.stringify({
    id: 'webhook-replay',
    type: 'item.updated',
    timestamp: 1720000001,
    data: { itemId: 1 },
  });
  try {
    await post(server, '/webhook', rawBody, webhookHeaders(rawBody));
    const { status, body } = await post(server, '/webhook', rawBody, webhookHeaders(rawBody));
    assert.strictEqual(status, 409);
    assert.deepStrictEqual(body, { error: 'duplicate_event', id: 'webhook-replay' });
  } finally {
    server.close();
  }
});

test('POST /webhook rejects a replay before validating its second body', async () => {
  const server = await startServer();
  const acceptedBody = JSON.stringify({
    id: 'webhook-replay-invalid-body',
    type: 'item.updated',
    timestamp: 1720000004,
    data: { itemId: 1 },
  });
  const replayBody = JSON.stringify({ id: 'webhook-replay-invalid-body' });
  try {
    await post(server, '/webhook', acceptedBody, webhookHeaders(acceptedBody));
    const { status, body } = await post(server, '/webhook', replayBody, webhookHeaders(replayBody));
    assert.strictEqual(status, 409);
    assert.deepStrictEqual(body, { error: 'duplicate_event', id: 'webhook-replay-invalid-body' });
  } finally {
    server.close();
  }
});

test('POST /webhook rejects a tampered body with a stale signature', async () => {
  const server = await startServer();
  const rawBody = JSON.stringify({
    id: 'webhook-tampered',
    type: 'item.updated',
    timestamp: 1720000002,
    data: { itemId: 1 },
  });
  const tamperedBody = rawBody.replace('item.updated', 'item.deleted');
  try {
    const { status, body } = await post(server, '/webhook', tamperedBody, webhookHeaders(rawBody));
    assert.strictEqual(status, 401);
    assert.deepStrictEqual(body, { error: 'invalid_signature' });
  } finally {
    server.close();
  }
});

test('POST /webhook rejects a validly signed invalid body', async () => {
  const server = await startServer();
  const rawBody = JSON.stringify({ id: 'webhook-invalid-body' });
  try {
    const { status, body } = await post(server, '/webhook', rawBody, webhookHeaders(rawBody));
    assert.strictEqual(status, 400);
    assert.deepStrictEqual(body, { error: 'invalid_body' });
  } finally {
    server.close();
  }
});

test('POST /webhook rejects a malformed signature', async () => {
  const server = await startServer();
  const rawBody = JSON.stringify({
    id: 'webhook-malformed-signature',
    type: 'item.updated',
    timestamp: 1720000003,
    data: { itemId: 1 },
  });
  try {
    const { status, body } = await post(server, '/webhook', rawBody, {
      'Content-Type': 'application/json',
      'X-Signature': 'not-a-valid-signature',
    });
    assert.strictEqual(status, 401);
    assert.deepStrictEqual(body, { error: 'invalid_signature' });
  } finally {
    server.close();
  }
});
